"use client";

import React, { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { useUpdateSetting } from "@/shared/hooks/use-settings";
import type {
  AiNode,
  DbQueryConfig,
  Edge,
  ParserSampleState,
  PathConfig,
  PathDebugEntry,
  PathDebugSnapshot,
  RuntimeHistoryEntry,
  RuntimePortValues,
  RuntimeState,
  UpdaterSampleState,
} from "@/features/ai/ai-paths/lib";
import {
  PATH_DEBUG_PREFIX,
  STORAGE_VERSION,
  TRIGGER_EVENTS,
  aiJobsApi,
  coerceInput,
  entityApi,
  evaluateGraph,
  evaluateGraphWithIteratorAutoContinue,
  runsApi,
} from "@/features/ai/ai-paths/lib";
import { extractImageUrls } from "@/features/ai/ai-paths/lib/core/runtime/utils";
import {
  DEFAULT_DB_QUERY,
  pollDatabaseQuery,
  pollGraphJob,
  safeJsonStringify,
} from "../AiPathsSettingsUtils";

const AI_PATHS_SESSION_STALE_MS = 30_000;
const AI_PATHS_ENTITY_STALE_MS = 10_000;

type ToastFn = (message: string, options?: Partial<{ variant: "success" | "error" | "info"; duration: number }>) => void;

type UseAiPathsRuntimeArgs = {
  activePathId: string | null;
  activeTab: "canvas" | "paths" | "docs";
  isPathActive: boolean;
  activeTrigger: string;
  edges: Edge[];
  nodes: AiNode[];
  pathDescription: string;
  pathName: string;
  parserSamples: Record<string, ParserSampleState>;
  updaterSamples: Record<string, UpdaterSampleState>;
  runtimeState: RuntimeState;
  lastRunAt: string | null;
  setLastRunAt: (value: string | null) => void;
  setPathConfigs: React.Dispatch<React.SetStateAction<Record<string, PathConfig>>>;
  setPathDebugSnapshots: React.Dispatch<
    React.SetStateAction<Record<string, PathDebugSnapshot>>
  >;
  setRuntimeState: React.Dispatch<React.SetStateAction<RuntimeState>>;
  toast: ToastFn;
  reportAiPathsError: (
    error: unknown,
    context: Record<string, unknown>,
    fallbackMessage?: string
  ) => void;
};

type UseAiPathsRuntimeResult = {
  handleRunSimulation: (simulationNode: AiNode, triggerEvent?: string) => Promise<void>;
  handleFireTrigger: (triggerNode: AiNode, event?: React.MouseEvent) => void;
  handleFireTriggerPersistent: (
    triggerNode: AiNode,
    event?: React.MouseEvent
  ) => Promise<void>;
  handleSendToAi: (sourceNodeId: string, prompt: string) => Promise<void>;
  sendingToAi: boolean;
};

export function useAiPathsRuntime({
  activePathId,
  activeTab,
  isPathActive,
  activeTrigger,
  edges,
  nodes,
  pathDescription,
  pathName,
  parserSamples,
  updaterSamples,
  runtimeState,
  lastRunAt,
  setLastRunAt,
  setPathConfigs,
  setPathDebugSnapshots,
  setRuntimeState,
  toast,
  reportAiPathsError,
}: UseAiPathsRuntimeArgs): UseAiPathsRuntimeResult {
  const [sendingToAi, setSendingToAi] = useState(false);

  const pollInFlightRef = useRef<Set<string>>(new Set());
  const iteratorContinueInFlightRef = useRef(false);
  const lastTriggerNodeIdRef = useRef<string | null>(null);
  const triggerContextRef = useRef<Record<string, unknown> | null>(null);
  const pendingSimulationContextRef = useRef<Record<string, unknown> | null>(null);
  const runtimeStateRef = useRef<RuntimeState>({ inputs: {}, outputs: {} });
  const queryClient = useQueryClient();
  const updateSettingMutation = useUpdateSetting();

  const enqueueAiJobMutation = useMutation({
    mutationFn: async (payload: {
      productId: string;
      type: string;
      payload: unknown;
    }): Promise<unknown> => {
      const result = await aiJobsApi.enqueue(payload);
      if (!result.ok) {
        throw new Error(result.error || "Failed to enqueue AI job.");
      }
      return result.data;
    },
  });

  const sessionQuery = useQuery({
    queryKey: ["auth-session"],
    queryFn: async () => {
      const res = await fetch("/api/auth/session");
      if (!res.ok) return null;
      return (await res.json()) as {
        user?: { id?: string; name?: string | null; email?: string | null };
      };
    },
    staleTime: AI_PATHS_SESSION_STALE_MS,
  });

  const sessionUser = useMemo(() => {
    const user = sessionQuery.data?.user;
    if (!user) return null;
    return {
      id: user.id,
      name: user.name ?? null,
      email: user.email ?? null,
    };
  }, [sessionQuery.data]);

  useEffect((): void => {
    runtimeStateRef.current = runtimeState;
  }, [runtimeState]);

  const fetchProductById = useCallback(
    async (productId: string): Promise<Record<string, unknown> | null> => {
      try {
        return await queryClient.fetchQuery({
          queryKey: ["products", productId],
          queryFn: async (): Promise<Record<string, unknown> | null> => {
            const result = await entityApi.getProduct(productId);
            return result.ok ? result.data : null;
          },
          staleTime: AI_PATHS_ENTITY_STALE_MS,
        });
      } catch (error) {
        reportAiPathsError(error, { action: "fetchProduct", productId }, "Failed to fetch product:");
        return null;
      }
    },
    [queryClient, reportAiPathsError]
  );

  const fetchNoteById = useCallback(
    async (noteId: string): Promise<Record<string, unknown> | null> => {
      try {
        return await queryClient.fetchQuery({
          queryKey: ["notes", noteId],
          queryFn: async (): Promise<Record<string, unknown> | null> => {
            const result = await entityApi.getNote(noteId);
            return result.ok ? result.data : null;
          },
          staleTime: AI_PATHS_ENTITY_STALE_MS,
        });
      } catch (error) {
        reportAiPathsError(error, { action: "fetchNote", noteId }, "Failed to fetch note:");
        return null;
      }
    },
    [queryClient, reportAiPathsError]
  );

  const normalizeEntityType = (value?: string | null): string | null => {
    const normalized = value?.trim().toLowerCase();
    if (!normalized) return null;
    if (normalized === "product" || normalized === "products") return "product";
    if (normalized === "note" || normalized === "notes") return "note";
    return normalized;
  };

  const fetchEntityByType = useCallback(
    async (entityType: string, entityId: string): Promise<Record<string, unknown> | null> => {
      if (!entityType || !entityId) return null;
      const normalized = normalizeEntityType(entityType);
      if (normalized === "product") {
        return fetchProductById(entityId);
      }
      if (normalized === "note") {
        return fetchNoteById(entityId);
      }
      return null;
    },
    [fetchProductById, fetchNoteById]
  );

  const buildActivePathConfig = useCallback(
    (updatedAt: string): PathConfig => ({
      id: activePathId ?? "default",
      version: STORAGE_VERSION,
      name: pathName,
      description: pathDescription,
      trigger: activeTrigger,
      nodes,
      edges,
      updatedAt,
      parserSamples,
      updaterSamples,
      runtimeState,
      lastRunAt,
    }),
    [
      activePathId,
      pathName,
      pathDescription,
      activeTrigger,
      nodes,
      edges,
      parserSamples,
      updaterSamples,
      runtimeState,
      lastRunAt,
    ]
  );

  const getDomSelector = (element: Element | null): string | null => {
    if (!element) return null;
    const selectorEscape = (val: string): string => {
      if (typeof CSS !== "undefined" && typeof CSS.escape === "function") {
        return CSS.escape(val);
      }
      return val.replace(/[^\w-]/g, "\\$&");
    };
    const dataSelector =
      element.getAttribute("data-component") ||
      element.getAttribute("data-testid") ||
      element.getAttribute("data-node");
    if (dataSelector) {
      const attr =
        element.getAttribute("data-component") !== null
          ? "data-component"
          : element.getAttribute("data-testid") !== null
            ? "data-testid"
            : "data-node";
      return `${element.tagName.toLowerCase()}[${attr}="${selectorEscape(dataSelector)}"]`;
    }
    if (element.id) {
      return `#${selectorEscape(element.id)}`;
    }
    const segments: string[] = [];
    let current: Element | null = element;
    while (current && current.tagName.toLowerCase() !== "html" && segments.length < 5) {
      const tagName = current.tagName.toLowerCase();
      const parent: HTMLElement | null = current.parentElement;
      if (!parent) break;
      const siblings: Element[] = Array.from(parent.children).filter(
        (child: Element): boolean => child.tagName === (current as Element).tagName
      );
      const index: number = siblings.indexOf(current) + 1;
      segments.unshift(`${tagName}:nth-of-type(${index})`);
      if (parent.id) {
        segments.unshift(`#${selectorEscape(parent.id)}`);
        break;
      }
      current = parent as Element;
    }
    return segments.length ? segments.join(" > ") : element.tagName.toLowerCase();
  };

  const getTargetInfo = (event?: React.MouseEvent): Record<string, unknown> | null => {
    const target = event?.target as Element | null;
    if (!target) return null;
    const element =
      target.closest(
        "[data-component],[data-testid],[data-node],button,a,[role='button']"
      ) ?? target;
    const rect = element.getBoundingClientRect();
    const dataset = element instanceof HTMLElement ? element.dataset : undefined;
    return {
      tagName: element.tagName.toLowerCase(),
      id: element.id || undefined,
      className: element.getAttribute("class") || undefined,
      name: element.getAttribute("name") || undefined,
      type: element.getAttribute("type") || undefined,
      role: element.getAttribute("role") || undefined,
      ariaLabel: element.getAttribute("aria-label") || undefined,
      dataComponent: element.getAttribute("data-component") || undefined,
      dataTestId: element.getAttribute("data-testid") || undefined,
      dataNode: element.getAttribute("data-node") || undefined,
      selector: getDomSelector(element),
      boundingClientRect: {
        x: rect.x,
        y: rect.y,
        width: rect.width,
        height: rect.height,
        top: rect.top,
        left: rect.left,
        right: rect.right,
        bottom: rect.bottom,
      },
      dataset: dataset ? { ...dataset } : undefined,
    };
  };

  const buildDebugSnapshot = useCallback(
    (pathId: string | null, runAt: string, state: RuntimeState): PathDebugSnapshot | null => {
      if (!pathId) return null;
      const entries = nodes
        .filter((node: AiNode): boolean => node.type === "database")
        .map((node: AiNode): PathDebugEntry | null => {
          const output = state.outputs[node.id] as
            | { debugPayload?: unknown }
            | undefined;
          const debugPayload = output?.debugPayload;
          if (debugPayload === undefined || debugPayload === null) return null;
          return {
            nodeId: node.id,
            title: node.title,
            debug: debugPayload,
          };
        })
        .filter((entry: PathDebugEntry | null): entry is PathDebugEntry => entry !== null);
      if (entries.length === 0) return null;
      return { pathId, runAt, entries };
    },
    [nodes]
  );

  const persistDebugSnapshot = useCallback(
    async (pathId: string | null, runAt: string, state: RuntimeState): Promise<void> => {
      if (!pathId) return;
      const snapshot = buildDebugSnapshot(pathId, runAt, state);
      if (!snapshot) return;
      const payload = safeJsonStringify(snapshot);
      if (!payload) return;
      try {
        await updateSettingMutation.mutateAsync({
          key: `${PATH_DEBUG_PREFIX}${pathId}`,
          value: payload,
        });
        setPathDebugSnapshots((prev: Record<string, PathDebugSnapshot>) => ({
          ...prev,
          [pathId]: snapshot,
        }));
      } catch (error) {
        console.warn("[AI Paths] Failed to persist debug snapshot.", error);
      }
    },
    [buildDebugSnapshot, updateSettingMutation, setPathDebugSnapshots]
  );

  const buildTriggerContext = (
    triggerNode: AiNode,
    triggerEvent: string,
    event?: React.MouseEvent
  ): Record<string, unknown> => {
    const timestamp = new Date().toISOString();
    const nativeEvent = event?.nativeEvent;
    const pointer = nativeEvent
      ? {
          clientX: nativeEvent.clientX,
          clientY: nativeEvent.clientY,
          pageX: nativeEvent.pageX,
          pageY: nativeEvent.pageY,
          screenX: nativeEvent.screenX,
          screenY: nativeEvent.screenY,
          offsetX: "offsetX" in nativeEvent ? nativeEvent.offsetX : undefined,
          offsetY: "offsetY" in nativeEvent ? nativeEvent.offsetY : undefined,
          button: nativeEvent.button,
          buttons: nativeEvent.buttons,
          altKey: nativeEvent.altKey,
          ctrlKey: nativeEvent.ctrlKey,
          shiftKey: nativeEvent.shiftKey,
          metaKey: nativeEvent.metaKey,
        }
      : undefined;
    const targetInfo = getTargetInfo(event);
    const location =
      typeof window !== "undefined"
        ? {
            href: window.location.href,
            origin: window.location.origin,
            pathname: window.location.pathname,
            search: window.location.search,
            hash: window.location.hash,
            referrer: document.referrer || undefined,
          }
        : {};
    const ui =
      typeof window !== "undefined"
        ? {
            viewport: {
              width: window.innerWidth,
              height: window.innerHeight,
              devicePixelRatio: window.devicePixelRatio,
            },
            screen: {
              width: window.screen?.width,
              height: window.screen?.height,
              availWidth: window.screen?.availWidth,
              availHeight: window.screen?.availHeight,
            },
            userAgent: navigator.userAgent,
            platform: navigator.platform,
            language: navigator.language,
            languages: navigator.languages,
            timeZone: Intl.DateTimeFormat().resolvedOptions().timeZone,
            documentTitle: document.title,
            visibilityState: document.visibilityState,
            scroll: {
              x: window.scrollX,
              y: window.scrollY,
            },
          }
        : {};
    return {
      timestamp,
      location,
      ui,
      user: sessionUser,
      event: {
        id: triggerEvent,
        nodeId: triggerNode.id,
        nodeTitle: triggerNode.title,
        type: event?.type,
        pointer,
        target: targetInfo,
      },
      source: {
        pathId: activePathId,
        pathName,
        tab: activeTab,
      },
      extras: {
        triggerLabel: activeTrigger,
      },
    };
  };

  const runGraphForTrigger = useCallback(async (
    triggerNode: AiNode,
    event?: React.MouseEvent,
    contextOverride?: Record<string, unknown>
  ): Promise<void> => {
    if (!isPathActive) {
      toast("This path is deactivated. Activate it to run.", { variant: "info" });
      return;
    }
    const triggerEvent =
      triggerNode.config?.trigger?.event ??
      TRIGGER_EVENTS[0]?.id ??
      "manual";
    lastTriggerNodeIdRef.current = triggerNode.id;
    const triggerContext = {
      ...buildTriggerContext(triggerNode, triggerEvent, event),
      ...(pendingSimulationContextRef.current ?? {}),
      ...(contextOverride ?? {}),
    };
    triggerContextRef.current = triggerContext;
    pendingSimulationContextRef.current = null;
    const result = await evaluateGraphWithIteratorAutoContinue({
      nodes,
      edges,
      activePathId,
      activePathName: pathName,
      triggerNodeId: triggerNode.id,
      triggerEvent,
      triggerContext,
      deferPoll: true,
      recordHistory: true,
      historyLimit: 50,
      seedHistory: runtimeStateRef.current.history ?? undefined,
      fetchEntityByType,
      reportAiPathsError,
      toast,
    });
    const runAt = new Date().toISOString();
    setRuntimeState(result);
    setLastRunAt(runAt);
    void persistDebugSnapshot(activePathId ?? null, runAt, result);
    if (activePathId) {
      setPathConfigs((prev: Record<string, PathConfig>) => ({
        ...prev,
        [activePathId]: {
          ...(prev[activePathId] ?? buildActivePathConfig(runAt)),
          runtimeState: result,
          lastRunAt: runAt,
        },
      }));
    }

  }, [isPathActive, buildTriggerContext, nodes, edges, activePathId, pathName, fetchEntityByType, reportAiPathsError, toast, setRuntimeState, setLastRunAt, persistDebugSnapshot, setPathConfigs, buildActivePathConfig]);

  const runPollUpdate = useCallback(
    async (
      node: AiNode,
      options: {
        jobId?: string;
        nodeInputs: RuntimePortValues;
      }
    ): Promise<void> => {
      const fallbackJobId = options.jobId;
      const pollKey = `${node.id}:${options.jobId ?? "db"}`;
      if (pollInFlightRef.current.has(pollKey)) return;
      pollInFlightRef.current.add(pollKey);
      try {
        const pollConfig = node.config?.poll;
        const pollMode = pollConfig?.mode ?? "job";
        let pollOutput: RuntimePortValues | null = null;
        if (pollMode === "database") {
          const queryConfig: DbQueryConfig = {
            ...DEFAULT_DB_QUERY,
            ...(pollConfig?.dbQuery ?? {}),
          };
          const response = await pollDatabaseQuery(options.nodeInputs, {
            intervalMs: pollConfig?.intervalMs ?? 2000,
            maxAttempts: pollConfig?.maxAttempts ?? 30,
            dbQuery: queryConfig,
            successPath: pollConfig?.successPath ?? "status",
            successOperator: pollConfig?.successOperator ?? "equals",
            successValue: pollConfig?.successValue ?? "completed",
            resultPath: pollConfig?.resultPath ?? "result",
          });
          pollOutput = {
            result: response.result,
            status: response.status,
            bundle: response.bundle,
          };
        } else {
          const jobId = options.jobId ?? "";
          if (!jobId) {
            return;
          }
          const result = await pollGraphJob(jobId, {
            intervalMs: pollConfig?.intervalMs ?? 2000,
            maxAttempts: pollConfig?.maxAttempts ?? 30,
          });

          pollOutput = {
            result,
            status: "completed",
            jobId,
            bundle: { jobId, status: "completed", result },
          };
        }
        const resolvedJobId =
          typeof pollOutput?.jobId === "string" ? pollOutput.jobId : fallbackJobId;
        const updatedOutputs: Record<string, RuntimePortValues> = {
          ...runtimeStateRef.current.outputs,
          [node.id]: pollOutput ?? runtimeStateRef.current.outputs[node.id] ?? {},
        };
        if (resolvedJobId) {
          nodes
            .filter((item: AiNode): boolean => item.type === "model")
            .forEach((modelNode: AiNode) => {
              const modelOutput = updatedOutputs[modelNode.id] as
                | { jobId?: string; status?: string; result?: unknown; debugPayload?: unknown }
                | undefined;
              if (!modelOutput || modelOutput.jobId !== resolvedJobId) return;
              updatedOutputs[modelNode.id] = {
                ...modelOutput,
                status: pollOutput?.status ?? "completed",
                result:
                  pollOutput?.result !== undefined ? pollOutput.result : modelOutput.result,
              };
            });
        }
        setRuntimeState((prev: RuntimeState): RuntimeState => ({
          ...prev,
          outputs: updatedOutputs,
        }));
        const triggerNodeId = lastTriggerNodeIdRef.current ?? undefined;
        const seededOutputs = updatedOutputs;
        const downstreamState = await evaluateGraph({
          nodes,
          edges,
          activePathId,
          activePathName: pathName,
          ...(triggerNodeId ? { triggerNodeId } : {}),
          triggerContext: triggerContextRef.current,
          deferPoll: true,
          skipAiJobs: true,
          seedOutputs: seededOutputs,
          seedHashes: runtimeStateRef.current.hashes ?? undefined,
          seedHistory: runtimeStateRef.current.history ?? undefined,
          recordHistory: true,
          historyLimit: 50,
          fetchEntityByType,
          reportAiPathsError,
          toast,
        });
        const runAt = new Date().toISOString();
        setRuntimeState(downstreamState);
        setLastRunAt(runAt);
        void persistDebugSnapshot(activePathId ?? null, runAt, downstreamState);
        if (activePathId) {
          setPathConfigs((prev: Record<string, PathConfig>) => ({
            ...prev,
            [activePathId]: {
              ...(prev[activePathId] ?? buildActivePathConfig(runAt)),
              runtimeState: downstreamState,
              lastRunAt: runAt,
            },
          }));
        }

        // If the poll completion caused an Iterator to advance, start the next iteration (launch AI jobs).
        const shouldContinueIterators = nodes.some((n: AiNode): boolean => {
          if (n.type !== "iterator") return false;
          if (n.config?.iterator?.autoContinue === false) return false;
          const status = downstreamState.outputs[n.id]?.status;
          return status === "advance_pending";
        });
        if (shouldContinueIterators && !iteratorContinueInFlightRef.current) {
          iteratorContinueInFlightRef.current = true;
          try {
            const triggerNodeId = lastTriggerNodeIdRef.current ?? undefined;
            const continued = await evaluateGraphWithIteratorAutoContinue({
              nodes,
              edges,
              activePathId,
              activePathName: pathName,
              ...(triggerNodeId ? { triggerNodeId } : {}),
              triggerContext: triggerContextRef.current,
              deferPoll: true,
              recordHistory: true,
              historyLimit: 50,
              seedOutputs: downstreamState.outputs,
              seedHashes: downstreamState.hashes ?? undefined,
              seedHistory: downstreamState.history ?? undefined,
              fetchEntityByType,
              reportAiPathsError,
              toast,
            });
            const continuedAt = new Date().toISOString();
            setRuntimeState(continued);
            setLastRunAt(continuedAt);
            void persistDebugSnapshot(activePathId ?? null, continuedAt, continued);
            if (activePathId) {
              setPathConfigs((prev: Record<string, PathConfig>) => ({
                ...prev,
                [activePathId]: {
                  ...(prev[activePathId] ?? buildActivePathConfig(continuedAt)),
                  runtimeState: continued,
                  lastRunAt: continuedAt,
                },
              }));
            }
          } finally {
            iteratorContinueInFlightRef.current = false;
          }
        }
      } catch (error) {
        reportAiPathsError(
          error,
          { action: "pollJob", nodeId: node.id, jobId: fallbackJobId },
          "AI job polling failed:"
        );
        setRuntimeState((prev: RuntimeState): RuntimeState => ({
          ...prev,
          outputs: {
            ...prev.outputs,
            [node.id]: {
              result: null,
              status: "failed",
              jobId: fallbackJobId,
              bundle: {
                jobId: fallbackJobId,
                status: "failed",
                error: error instanceof Error ? error.message : "Polling failed",
              },
            },
          },
        }));
      } finally {
        pollInFlightRef.current.delete(pollKey);
      }
    },
    [
      nodes,
      edges,
      activePathId,
      pathName,
      fetchEntityByType,
      reportAiPathsError,
      toast,
      persistDebugSnapshot,
      buildActivePathConfig,
      setPathConfigs,
      setRuntimeState,
      setLastRunAt,
    ]
  );

  const startPendingPolls = useCallback(
    (state: RuntimeState): void => {
      nodes
        .filter((node: AiNode): boolean => node.type === "poll")
        .forEach((node: AiNode) => {
          const pollConfig = node.config?.poll;
          const output = state.outputs[node.id] as
            | { status?: string; jobId?: string }
            | undefined;
          const nodeInputs = state.inputs[node.id] ?? {};
          const inputJobId = coerceInput(nodeInputs.jobId);
          const jobId =
            output?.jobId ??
            (typeof inputJobId === "string" || typeof inputJobId === "number"
              ? String(inputJobId).trim()
              : "");
          const status = output?.status ?? "polling";
          if (status === "completed" || status === "failed") return;
          if (pollConfig?.mode !== "database" && !jobId) return;
          void runPollUpdate(node, { jobId, nodeInputs });
        });
    },
    [nodes, runPollUpdate]
  );

  useEffect((): void => {
    if (!runtimeState || nodes.length === 0) return;
    startPendingPolls(runtimeState);
  }, [nodes, runtimeState, startPendingPolls]);

  const dispatchTrigger = (eventName: string, entityId: string, entityType?: string): void => {
    if (typeof window === "undefined") return;
    window.dispatchEvent(
      new CustomEvent("ai-path-trigger", {
        detail: {
          trigger: eventName,
          productId: entityId,
          entityId,
          entityType: entityType ?? "product",
        },
      })
    );
  };

  const handleRunSimulation = useCallback(
    async (simulationNode: AiNode, triggerEvent?: string): Promise<void> => {
      const entityId =
        simulationNode.config?.simulation?.entityId?.trim() ||
        simulationNode.config?.simulation?.productId?.trim();
      const entityType =
        normalizeEntityType(simulationNode.config?.simulation?.entityType) ?? "product";
      if (!entityId) {
        toast("Enter an Entity ID in the simulation node.", { variant: "error" });
        return;
      }
      const entity = await fetchEntityByType(entityType, entityId);
      const imageUrls = entity ? extractImageUrls(entity) : [];
      const simulationContext: Record<string, unknown> = {
        entityId,
        entityType,
        ...(entityType === "product" ? { productId: entityId } : {}),
        ...(imageUrls.length ? { images: imageUrls, imageUrls } : {}),
        ...(entity ? { entity } : {}),
      };
      pendingSimulationContextRef.current = simulationContext;
      let eventName = triggerEvent ?? TRIGGER_EVENTS[0]?.id ?? "manual";
      if (!triggerEvent) {
        const connectedTriggerIds = edges.flatMap((edge: Edge): string[] => {
          if (
            edge.from === simulationNode.id &&
            (!edge.fromPort || edge.fromPort === "context" || edge.fromPort === "simulation")
          ) {
            return [edge.to];
          }
          if (
            edge.to === simulationNode.id &&
            (!edge.toPort || edge.toPort === "trigger")
          ) {
            return [edge.from];
          }
          return [];
        });
        const triggerNode = nodes.find(
          (node: AiNode): boolean =>
            node.type === "trigger" && connectedTriggerIds.includes(node.id)
        );
        if (triggerNode) {
          eventName = triggerNode.config?.trigger?.event ?? eventName;
          await runGraphForTrigger(triggerNode, undefined, simulationContext);
        }
      }
      dispatchTrigger(eventName, entityId, entityType);
      if (!entity) {
        toast(`No entity found for ${entityType} ${entityId}. Using fallback context.`, {
          variant: "info",
        });
      }
      toast(`Simulated ${eventName} for ${entityType} ${entityId}`, {
        variant: "success",
      });
    },
    [edges, fetchEntityByType, nodes, runGraphForTrigger, toast]
  );

  const handleFireTrigger = (triggerNode: AiNode, event?: React.MouseEvent): void => {
    void (async (): Promise<void> => {
      const triggerEvent = triggerNode.config?.trigger?.event ?? TRIGGER_EVENTS[0]?.id;
      const isScheduled = triggerEvent === "scheduled_run";
      const connectedSimulationIds = edges.flatMap((edge: Edge): string[] => {
        if (
          edge.to === triggerNode.id &&
          (!edge.toPort || edge.toPort === "context" || edge.toPort === "simulation") &&
          (!edge.fromPort || edge.fromPort === "context" || edge.fromPort === "simulation")
        ) {
          return [edge.from];
        }
        if (
          edge.from === triggerNode.id &&
          (!edge.fromPort || edge.fromPort === "trigger") &&
          (!edge.toPort || edge.toPort === "trigger")
        ) {
          return [edge.to];
        }
        return [];
      });
      const simulationNodes = nodes.filter(
        (node: AiNode): boolean =>
          node.type === "simulation" && connectedSimulationIds.includes(node.id)
      );
      if (simulationNodes.length === 0) {
        if (!isScheduled) {
          toast("Connect a Simulation node to the Trigger context input.", {
            variant: "error",
          });
          return;
        }
        await runGraphForTrigger(triggerNode, event);
        return;
      }
      for (const node of simulationNodes) {
        await handleRunSimulation(node, triggerEvent);
      }
      await runGraphForTrigger(triggerNode, event, pendingSimulationContextRef.current ?? undefined);
    })();
  };

  const handleFireTriggerPersistent = async (
    triggerNode: AiNode,
    event?: React.MouseEvent
  ): Promise<void> => {
    const triggerEvent = triggerNode.config?.trigger?.event ?? TRIGGER_EVENTS[0]?.id;
    const isScheduled = triggerEvent === "scheduled_run";
    const connectedSimulationIds = edges.flatMap((edge: Edge): string[] => {
      if (
        edge.to === triggerNode.id &&
        (!edge.toPort || edge.toPort === "context" || edge.toPort === "simulation") &&
        (!edge.fromPort || edge.fromPort === "context" || edge.fromPort === "simulation")
      ) {
        return [edge.from];
      }
      if (
        edge.from === triggerNode.id &&
        (!edge.fromPort || edge.fromPort === "trigger") &&
        (!edge.toPort || edge.toPort === "trigger")
      ) {
        return [edge.to];
      }
      return [];
    });
    const simulationNodes = nodes.filter(
      (node: AiNode): boolean =>
        node.type === "simulation" && connectedSimulationIds.includes(node.id)
    );
    if (simulationNodes.length === 0) {
      if (!isScheduled) {
        toast("Connect a Simulation node to the Trigger context input.", {
          variant: "error",
        });
        return;
      }
      const triggerContext = buildTriggerContext(triggerNode, triggerEvent ?? "", event);
      const enqueueResult = await runsApi.enqueue({
        pathId: activePathId ?? "default",
        pathName,
        nodes,
        edges,
        ...(triggerEvent ? { triggerEvent } : {}),
        triggerNodeId: triggerNode.id,
        triggerContext,
        meta: {
          source: "ai_paths_ui",
        },
      });
      if (!enqueueResult.ok) {
        toast(enqueueResult.error || "Failed to enqueue persistent run.", {
          variant: "error",
        });
        return;
      }
      toast("Persistent run queued.", { variant: "success" });
      return;
    }
    const primarySimulation = simulationNodes[0]!;
    const entityId =
      primarySimulation.config?.simulation?.entityId?.trim() ||
      primarySimulation.config?.simulation?.productId?.trim() ||
      "";
    const entityType = primarySimulation.config?.simulation?.entityType?.trim() || "product";
    if (!entityId) {
      toast("Simulation node is missing an Entity ID.", { variant: "error" });
      return;
    }
    const triggerContext = {
      ...buildTriggerContext(triggerNode, triggerEvent ?? "", event),
      entityId,
      entityType,
    };
    const enqueueResult = await runsApi.enqueue({
      pathId: activePathId ?? "default",
      pathName,
      nodes,
      edges,
      ...(triggerEvent ? { triggerEvent } : {}),
      triggerNodeId: triggerNode.id,
      triggerContext,
      entityId,
      entityType,
      meta: {
        source: "ai_paths_ui",
      },
    });
    if (!enqueueResult.ok) {
      toast(enqueueResult.error || "Failed to enqueue persistent run.", {
        variant: "error",
      });
      return;
    }
    toast("Persistent run queued.", { variant: "success" });
  };

  const handleSendToAi = async (sourceNodeId: string, prompt: string): Promise<void> => {
    // Find the source node to determine its type
    const sourceNode = nodes.find((n: AiNode): boolean => n.id === sourceNodeId);
    if (!sourceNode) {
      toast("Source node not found.", { variant: "error" });
      return;
    }

    // Find the connected AI Model node
    // For database nodes, prefer aiPrompt port; for prompt nodes, prefer prompt port; but accept any connection to a model
    const preferredPort =
      sourceNode.type === "database" || sourceNode.type === "regex"
        ? "aiPrompt"
        : "prompt";

    // First try to find edge with preferred port
    let aiEdge = edges.find(
      (edge: Edge): boolean => edge.from === sourceNodeId && edge.fromPort === preferredPort
    );

    // If not found, find any edge that connects to a model node
    if (!aiEdge) {
      aiEdge = edges.find((edge: Edge): boolean => {
        if (edge.from !== sourceNodeId) return false;
        const targetNode = nodes.find((n: AiNode): boolean => n.id === edge.to);
        return targetNode?.type === "model";
      });
    }

    if (!aiEdge) {
      toast("No AI Model connected.", { variant: "error" });
      return;
    }
    const aiNode = nodes.find((n: AiNode): boolean => n.id === aiEdge.to && n.type === "model");
    if (!aiNode) {
      toast("Connected node is not an AI Model.", { variant: "error" });
      return;
    }
    const modelConfig = aiNode.config?.model ?? {
      modelId: "gpt-4o",
      temperature: 0.7,
      maxTokens: 800,
      vision: false,
    };
    setSendingToAi(true);
    try {
      const payload = {
        prompt: prompt.trim(),
        imageUrls: [],
        modelId: modelConfig.modelId,
        temperature: modelConfig.temperature,
        maxTokens: modelConfig.maxTokens,
        vision: modelConfig.vision,
        source: "ai_paths_direct",
        graph: {
          pathId: activePathId ?? undefined,
          nodeId: aiNode.id,
          nodeTitle: aiNode.title,
        },
      };
      const enqueueData = (await enqueueAiJobMutation.mutateAsync({
        productId: activePathId ?? "direct",
        type: "graph_model",
        payload,
      })) as { jobId: string };
      toast("AI job queued. Waiting for result...", { variant: "success" });
      const result = await pollGraphJob(enqueueData.jobId);
      // Update runtime state with the result
      setRuntimeState((prev: RuntimeState): RuntimeState => {
        const sourceInputs = prev.inputs[sourceNodeId] ?? {};
        const sourceOutputs = prev.outputs[sourceNodeId] ?? {};
        const aiOutputs = prev.outputs[aiNode.id] ?? {};
        const now = new Date().toISOString();
        const historyLimit = 50;

        // For database nodes, store result in queryCallback (both input and output)
        // For prompt nodes, store result in the result input (so it shows in the Result Input field)
        const updatedSourceOutputs =
          sourceNode.type === "database"
            ? { ...sourceOutputs, queryCallback: result }
            : sourceNode.type === "regex"
              ? { ...sourceOutputs, regexCallback: result }
              : sourceOutputs;

        const updatedSourceInputs =
          sourceNode.type === "database"
            ? { ...sourceInputs, queryCallback: result }
            : sourceNode.type === "prompt"
              ? { ...sourceInputs, result }
              : sourceNode.type === "regex"
                ? { ...sourceInputs, regexCallback: result }
              : sourceInputs;

        const nextHistory: Record<string, RuntimeHistoryEntry[]> = prev.history
          ? { ...prev.history }
          : {};
        const pushHistory = (
          node: AiNode,
          inputs: RuntimePortValues,
          outputs: RuntimePortValues
        ): void => {
          const entry: RuntimeHistoryEntry = {
            timestamp: now,
            pathId: activePathId ?? null,
            pathName: pathName ?? null,
            nodeId: node.id,
            nodeType: node.type,
            nodeTitle: node.title ?? null,
            status: "completed",
            inputs,
            outputs,
          };
          const existing = nextHistory[node.id] ? [...nextHistory[node.id]!] : [];
          existing.push(entry);
          if (existing.length > historyLimit) {
            existing.splice(0, existing.length - historyLimit);
          }
          nextHistory[node.id] = existing;
        };
        pushHistory(sourceNode, updatedSourceInputs, updatedSourceOutputs);
        pushHistory(aiNode, {
          prompt: payload.prompt,
          modelId: modelConfig.modelId,
          temperature: modelConfig.temperature,
          maxTokens: modelConfig.maxTokens,
          vision: modelConfig.vision,
        }, {
          ...aiOutputs,
          result,
          jobId: enqueueData.jobId,
          status: "completed",
        });

        return {
          ...prev,
          inputs: {
            ...prev.inputs,
            [sourceNodeId]: updatedSourceInputs,
          },
          outputs: {
            ...prev.outputs,
            [sourceNodeId]: updatedSourceOutputs,
            [aiNode.id]: {
              ...aiOutputs,
              result,
              jobId: enqueueData.jobId,
              status: "completed",
            },
          },
          ...(Object.keys(nextHistory).length > 0 ? { history: nextHistory } : {}),
        };
      });
      toast("AI response received.", { variant: "success" });
    } catch (error) {
      reportAiPathsError(
        error,
        { action: "sendToAi", nodeId: sourceNodeId },
        "Send to AI failed:"
      );
      toast("Send to AI failed.", { variant: "error" });
    } finally {
      setSendingToAi(false);
    }
  };

  return {
    handleRunSimulation,
    handleFireTrigger,
    handleFireTriggerPersistent,
    handleSendToAi,
    sendingToAi,
  };
}

"use client";

import { useMemo, useState } from "react";
import { usePathname, useRouter, useSearchParams } from "next/navigation";
import {
  Button,
  ListPanel,
  UnifiedSelect,
  Label,
  Checkbox,
  Switch,
  ConfirmDialog,
  EmptyState,
  SearchInput,
  SharedModal,
} from "@/shared/ui"; // Removed SectionHeader
import { AdminPageLayout } from "@/shared/components/AdminPageLayout"; // Added import
import Link from "next/link";

import {
  useCmsAllSlugs,
  useCmsSlugs,
  useCreateSlug,
  useDeleteSlug,
} from "@/features/cms/hooks/useCmsQueries";
import { useCmsDomainSelection } from "@/features/cms/hooks/useCmsDomainSelection";
import { useUpdateSetting } from "@/shared/hooks/use-settings";
import { useSettingsStore } from "@/shared/providers/SettingsStoreProvider";
import { parseJsonSetting, serializeSetting } from "@/shared/utils/settings-json";
import { CMS_DOMAIN_SETTINGS_KEY, normalizeCmsDomainSettings } from "@/features/cms/types/domain-settings";
import { logClientError } from "@/shared/utils/observability/client-error-logger";
import type { CmsDomain, Slug } from "@/features/cms/types";
import { useCallback } from "react";

export default function SlugsPage(): React.JSX.Element {
  const router = useRouter();
  const pathname = usePathname();
  const searchParams = useSearchParams();
  const domainIdParam = searchParams.get("domainId") ?? undefined;
  const {
    domains,
    activeDomainId,
    hostDomainId,
    canonicalDomain,
    sharedWithDomains,
    setActiveDomainId,
    zoningEnabled,
  } = useCmsDomainSelection({ initialDomainId: domainIdParam ?? null });
  const settingsStore = useSettingsStore();
  const updateSetting = useUpdateSetting();
  const domainSettingsRaw = settingsStore.get(CMS_DOMAIN_SETTINGS_KEY);
  const domainSettings = useMemo(
    () =>
      normalizeCmsDomainSettings(
        parseJsonSetting(domainSettingsRaw, null)
      ),
    [domainSettingsRaw]
  );
  const zoningToggleValue = domainSettings.zoningEnabled;
  const [attachOpen, setAttachOpen] = useState(false);
  const [attachSelectedIds, setAttachSelectedIds] = useState<string[]>([]);
  const [slugToDelete, setSlugToDelete] = useState<Slug | null>(null);
  const [attachSearch, setAttachSearch] = useState("");
  const [attachError, setAttachError] = useState("");
  const slugsQuery = useCmsSlugs(activeDomainId);
  const allSlugsQuery = useCmsAllSlugs(attachOpen);
  const createSlug = useCreateSlug();
  const deleteSlug = useDeleteSlug();
  const slugs = useMemo((): Slug[] => slugsQuery.data ?? [], [slugsQuery.data]);
  const allSlugs = useMemo((): Slug[] => allSlugsQuery.data ?? [], [allSlugsQuery.data]);

  const handleDomainChange = (value: string): void => {
    const params = new URLSearchParams(searchParams.toString());
    if (value) {
      params.set("domainId", value);
    } else {
      params.delete("domainId");
    }
    const next = params.toString();
    router.replace(next ? `${pathname}?${next}` : pathname);
    setActiveDomainId(value || null);
  };

  const handleZoningToggle = (checked: boolean): void => {
    const next = normalizeCmsDomainSettings({ ...domainSettings, zoningEnabled: checked });
    updateSetting.mutate({ key: CMS_DOMAIN_SETTINGS_KEY, value: serializeSetting(next) });
  };

  const buildDomainHref = useMemo((): ((href: string) => string) => {
    return (href: string): string =>
      activeDomainId ? `${href}?domainId=${encodeURIComponent(activeDomainId)}` : href;
  }, [activeDomainId]);

  const availableAttachSlugs = useMemo((): Slug[] => {
    const assigned = new Set(slugs.map((slug: Slug) => slug.id));
    const base = allSlugs.filter((slug: Slug) => !assigned.has(slug.id));
    const term = attachSearch.trim().toLowerCase();
    if (!term) return base;
    return base.filter((slug: Slug) => slug.slug.toLowerCase().includes(term));
  }, [allSlugs, slugs, attachSearch]);

  const selectedAttachCount = useMemo((): number => attachSelectedIds.length, [attachSelectedIds]);

  const toggleAttachSelection = (slugId: string): void => {
    setAttachSelectedIds((prev: string[]): string[] =>
      prev.includes(slugId) ? prev.filter((id: string): boolean => id !== slugId) : [...prev, slugId]
    );
  };

  const selectAllVisible = (): void => {
    const visibleIds = availableAttachSlugs.map((slug: Slug) => slug.id);
    setAttachSelectedIds((prev: string[]): string[] => Array.from(new Set([...prev, ...visibleIds])));
  };

  const clearSelection = (): void => {
    setAttachSelectedIds([]);
  };

  const handleAttach = async (): Promise<void> => {
    if (!attachSelectedIds.length) {
      setAttachError("Select at least one slug to attach.");
      return;
    }
    const selected = allSlugs.filter((item: Slug) => attachSelectedIds.includes(item.id));
    if (!selected.length) {
      setAttachError("Selected slugs are no longer available.");
      return;
    }
    setAttachError("");
    for (const slug of selected) {
      await createSlug.mutateAsync({ slug: slug.slug, domainId: activeDomainId });
    }
    setAttachSelectedIds([]);
    setAttachSearch("");
    setAttachOpen(false);
  };

  const handleDelete = useCallback((slug: Slug): void => {
    setSlugToDelete(slug);
  }, []);

  const handleConfirmDelete = async (): Promise<void> => {
    if (!slugToDelete) return;
    try {
      await deleteSlug.mutateAsync({ id: slugToDelete.id, domainId: activeDomainId });
    } catch (error) {
      logClientError(error, { context: { source: "slugs-page", action: "deleteSlug", slugId: slugToDelete.id } });
    } finally {
      setSlugToDelete(null);
    }
  };

  return (
    <AdminPageLayout
      title="Slugs"
      description={
        zoningEnabled
          ? "Manage slugs assigned to the currently active domain. Slugs control routing for your CMS pages."
          : "Manage slugs for all domains. Slugs control routing for your CMS pages."
      }
      mainActions={
        <>
          <div className="flex items-center gap-2 rounded-md border border-border/60 bg-background/40 px-2 py-1">
            <Switch
              id="cms-domain-zoning"
              checked={zoningToggleValue}
              onCheckedChange={handleZoningToggle}
              disabled={updateSetting.isPending}
            />
            <Label htmlFor="cms-domain-zoning" className="text-xs text-muted-foreground">
              Domain zoning
            </Label>
          </div>
          {zoningEnabled ? (
            <UnifiedSelect
              value={activeDomainId || ""}
              onValueChange={handleDomainChange}
              options={domains.map((item: CmsDomain) => ({
                value: item.id,
                label: item.domain,
                description: hostDomainId === item.id ? "current" : undefined
              }))}
              placeholder="Current domain"
              className="w-[220px]"
              triggerClassName="h-9"
            />
          ) : (
            <span className="text-xs text-muted-foreground">Simple routing</span>
          )}
          {zoningEnabled ? (
            <Button variant="secondary" onClick={() => setAttachOpen(true)}>Attach Existing</Button>
          ) : null}
          <SharedModal
            open={attachOpen}
            onClose={(): void => {
              setAttachOpen(false);
              setAttachSelectedIds([]);
              setAttachSearch("");
              setAttachError("");
            }}
            title="Attach Existing Slug"
            size="md"
            footer={
              <>
                <Button
                  variant="secondary"
                  onClick={() => {
                    setAttachOpen(false);
                    setAttachSelectedIds([]);
                    setAttachSearch("");
                    setAttachError("");
                  }}
                >
                  Cancel
                </Button>
                <Button
                  onClick={() => { void handleAttach(); }}
                  disabled={selectedAttachCount === 0}
                >
                  Attach
                </Button>
              </>
            }
          >
            <div className="space-y-3">
              <div className="space-y-1">
                <Label htmlFor="attach-search">Search</Label>
                <SearchInput
                  id="attach-search"
                  value={attachSearch}
                  onChange={(event: React.ChangeEvent<HTMLInputElement>): void => setAttachSearch(event.target.value)}
                  onClear={() => setAttachSearch("")}
                  placeholder="Search slugs..."
                />
              </div>
              <div className="space-y-2">
                <div className="flex items-center justify-between">
                  <Label>Available slugs</Label>
                  <div className="flex items-center gap-2 text-xs text-muted-foreground">
                    <button
                      type="button"
                      className="hover:text-foreground"
                      onClick={selectAllVisible}
                    >
                      Select all
                    </button>
                    <span>•</span>
                    <button
                      type="button"
                      className="hover:text-foreground"
                      onClick={clearSelection}
                    >
                      Clear
                    </button>
                  </div>
                </div>
                <div className="max-h-56 overflow-y-auto rounded-md border border-border/60 bg-background/40 p-2">
                  {allSlugsQuery.isLoading ? (
                    <p className="py-6 text-center text-sm text-muted-foreground">
                      Loading slugs…
                    </p>
                  ) : availableAttachSlugs.length === 0 ? (
                    <p className="py-6 text-center text-sm text-muted-foreground">
                      No available slugs to attach.
                    </p>
                  ) : (
                    <ul className="space-y-2">
                      {availableAttachSlugs.map((slug: Slug) => (
                        <li key={slug.id} className="flex items-center gap-2">
                          <Checkbox
                            checked={attachSelectedIds.includes(slug.id)}
                            onCheckedChange={() => toggleAttachSelection(slug.id)}
                          />
                          <span className="text-sm">/{slug.slug}</span>
                        </li>
                      ))}
                    </ul>
                  )}
                </div>
                <p className="text-xs text-muted-foreground">
                  {selectedAttachCount} selected
                </p>
                {attachError ? (
                  <p className="text-sm text-red-500">{attachError}</p>
                ) : null}
              </div>
            </div>
          </SharedModal>
          <Button asChild>
            <Link href={buildDomainHref("/admin/cms/slugs/create")}>Create Slug</Link>
          </Button>
        </>
      }
    >
      <ListPanel
        header={null} // Header handled by AdminPageLayout
      >
        {slugs.length === 0 ? (
          <EmptyState
            title="No slugs assigned"
            description="Assign slugs to this domain to enable routing for your CMS pages."
            action={
              <div className="flex gap-2">
                <Button onClick={() => setAttachOpen(true)} variant="outline">
                  Attach Existing
                </Button>
                <Button asChild>
                  <Link href={buildDomainHref("/admin/cms/slugs/create")}>
                    Create New
                  </Link>
                </Button>
              </div>
            }
          />
        ) : (
          <ul>
            {slugs.map((slug: Slug) => (
              <li
                key={slug.id}
                className="flex justify-between items-center py-2 border-b border"
              >
                <Link href={buildDomainHref(`/admin/cms/slugs/${slug.id}/edit`)} className="flex flex-col">
                  <span className="hover:underline">
                    /{slug.slug} {slug.isDefault && "(Default)"}
                    {(canonicalDomain || sharedWithDomains.length > 0) ? (
                      <span className="ml-2 rounded-full bg-foreground/10 px-2 py-0.5 text-[11px] text-foreground/70">
                        Shared
                      </span>
                    ) : null}
                  </span>
                  {canonicalDomain ? (
                    <span className="text-xs text-muted-foreground">
                      Shared from {canonicalDomain.domain}
                    </span>
                  ) : sharedWithDomains.length > 0 ? (
                    <span className="text-xs text-muted-foreground">
                      Shared with {sharedWithDomains.map((item: CmsDomain) => item.domain).join(", ")}
                    </span>
                  ) : null}
                </Link>
                <Button
                  variant="destructive"
                  onClick={() => handleDelete(slug)}
                >
                  Remove from zone
                </Button>
              </li>
            ))}
          </ul>
        )}
      </ListPanel>

      <ConfirmDialog
        open={!!slugToDelete}
        onOpenChange={(open: boolean) => !open && setSlugToDelete(null)}
        onConfirm={(): void => { void handleConfirmDelete(); }}
        title="Remove Slug from Zone"
        description="Are you sure you want to remove this slug from the current zone? It will stay in other zones if assigned."
        confirmText="Remove"
        variant="destructive"
      />
    </AdminPageLayout>
  );
}

"use client";

import { DataTable, Button, useToast, SectionPanel, ConfirmDialog, FileUploadButton, type FileUploadHelpers } from "@/shared/ui"; // SectionHeader, Tabs, TabsList, TabsTrigger removed
import { AdminPageLayout } from "@/shared/components/AdminPageLayout"; // Added import
import { useState, useCallback } from "react";
import { useQueryClient } from "@tanstack/react-query";
import { logClientError } from "@/features/observability";

import { getDatabaseColumns } from "../components/DatabaseColumns";
import { LogModal } from "../components/LogModal";
import { RestoreModal } from "../components/RestoreModal";
import type { DatabaseInfo, DatabaseType } from "../types";
import {
  useDatabaseBackups,
  useCreateBackupMutation,
  useRestoreBackupMutation,
  useUploadBackupMutation,
  useDeleteBackupMutation,
} from "../hooks/useDatabaseQueries";


export default function DatabasesPage(): React.JSX.Element {
  const [activeTab, setActiveTab] = useState<DatabaseType>("postgresql");
  const [isLogModalOpen, setIsLogModalOpen] = useState(false);
  const [logModalContent, setLogModalContent] = useState("");
  const [isRestoreModalOpen, setIsRestoreModalOpen] = useState(false);
  const [selectedBackupForRestore, setSelectedBackupForRestore] = useState<string | null>(null);
  const [backupToDelete, setBackupToDelete] = useState<string | null>(null);
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const isProd = process.env.NODE_ENV === "production";

  const backupsQuery = useDatabaseBackups(activeTab);
  const data = backupsQuery.data ?? [];

  const createBackup = useCreateBackupMutation();
  const restoreBackup = useRestoreBackupMutation();
  const uploadBackup = useUploadBackupMutation();
  const deleteBackup = useDeleteBackupMutation();

  const openLogModal = useCallback((content: string): void => {
    setLogModalContent(content);
    setIsLogModalOpen(true);
  }, []);

  const closeLogModal = useCallback((): void => {
    setIsLogModalOpen(false);
    setLogModalContent("");
    void queryClient.invalidateQueries({ queryKey: ["database-backups", activeTab] });
  }, [queryClient, activeTab]);


  const handleRestoreRequest = useCallback((backup: DatabaseInfo): void => {
    setSelectedBackupForRestore(backup.name);
    setIsRestoreModalOpen(true);
  }, []);

  const handleRestoreConfirm = async (truncate: boolean): Promise<void> => {
    const backupName = selectedBackupForRestore;
    setIsRestoreModalOpen(false);
    setSelectedBackupForRestore(null);

    if (!backupName) return;

    try {
      const result = await restoreBackup.mutateAsync({
        dbType: activeTab,
        backupName,
        truncateBeforeRestore: truncate,
      });
      const { ok, payload } = result;
      const log = payload.log ?? "No log available.";

      if (ok) {
        openLogModal(
          `${payload.message ?? "Backup restored successfully."}\n\n---LOG---\n${log}`
        );
      } else {
        const meta = [
          payload.errorId ? `Error ID: ${payload.errorId}` : null,
          payload.stage ? `Stage: ${payload.stage}` : null,
          payload.backupName ? `Backup: ${payload.backupName}` : null,
        ]
          .filter(Boolean)
          .join("\n");

        openLogModal(
          `${payload.error ?? "Failed to restore backup."}${ 
            meta ? `\n\n${meta}` : "" 
          }\n\n---LOG---\n${log}`
        );
      }
    } catch (error: unknown) {
      logClientError(error, { context: { source: "DatabasesPage", action: "restoreBackup", backupName, dbType: activeTab } });
      openLogModal(`An error occurred during restoration.\n\n${String(error)}`);
    }
  };

  const handleBackup = async (): Promise<void> => {
    try {
      const result = await createBackup.mutateAsync(activeTab);
      const { ok, payload } = result;
      const log = payload.log ?? "No log available.";
      if (ok) {
        if (payload.warning) {
          openLogModal(
            `${payload.message ?? "Backup created"}: ${ 
              payload.warning 
            }\n\n---LOG---\n${log}`
          );
        } else {
          openLogModal(
            `${
              payload.message ?? "Backup created successfully."
            }\n\n---LOG---\n${log}`
          );
        }
      } else {
        openLogModal(
          `${payload.error ?? "Failed to create backup."}\n\n---LOG---\n${log}`
        );
      }
    } catch (error: unknown) {
      logClientError(error, { context: { source: "DatabasesPage", action: "createBackup", dbType: activeTab } });
      openLogModal(`An error occurred during backup.\n\n${String(error)}`);
    }
  };

  const handleDeleteRequest = useCallback((backupName: string): void => {
    setBackupToDelete(backupName);
  }, []);

  const handleConfirmDelete = async (): Promise<void> => {
    if (!backupToDelete) return;
    try {
      const result = await deleteBackup.mutateAsync({ dbType: activeTab, backupName: backupToDelete });
      if (result.ok) {
        toast("Backup deleted successfully.", { variant: "success" });
      } else {
        toast("Failed to delete backup.", { variant: "error" });
      }
    } catch (error: unknown) {
      logClientError(error, { context: { source: "DatabasesPage", action: "deleteBackup", backupName: backupToDelete, dbType: activeTab } });
      toast("An error occurred during deletion.", { variant: "error" });
    } finally {
      setBackupToDelete(null);
    }
  };

  const handleUpload = async (files: File[], helpers?: FileUploadHelpers): Promise<void> => {
    const file = files[0];
    if (!file) return;

    try {
      const result = await uploadBackup.mutateAsync({
        dbType: activeTab,
        file,
        onProgress: (loaded: number, total?: number) => helpers?.reportProgress(loaded, total),
      });
      if (result.ok) {
        toast("Backup uploaded successfully.", { variant: "success" });
      } else {
        toast("Failed to upload backup.", { variant: "error" });
      }
    } catch (error: unknown) {
      logClientError(error, { context: { source: "DatabasesPage", action: "uploadBackup", filename: file.name, dbType: activeTab } });
      toast("An error occurred during upload.", { variant: "error" });
    }
  };

  const handlePreview = (backupName: string): void => {
    const url = `/admin/databases/preview?backup=${encodeURIComponent(
      backupName
    )}&type=${activeTab}`;
    window.location.assign(url);
  };

  const handlePreviewCurrent = (): void => {
    window.location.assign(`/admin/databases/preview?mode=current&type=${activeTab}`);
  };

  return (
    <AdminPageLayout
      title={`Databases - ${activeTab === "postgresql" ? "PostgreSQL" : "MongoDB"}`}
      description={
        activeTab === "postgresql"
          ? "PostgreSQL backups use pg_dump/pg_restore (.dump files). Restores are data-only and preserve your current schema."
          : "MongoDB backups use mongodump/mongorestore (.archive files). Full database dumps with BSON format."
      }
      mainActions={
        <>
          <Button
            disabled={isProd}
            title={isProd ? "Disabled in production" : undefined}
            onClick={(): void => {
              void handleBackup();
            }}
          >
            Create Backup
          </Button>
          <FileUploadButton
            onFilesSelected={(files: File[], helpers?: FileUploadHelpers) => handleUpload(files, helpers)}
            accept={activeTab === "postgresql" ? ".dump" : ".archive"}
            disabled={isProd}
            title={isProd ? "Disabled in production" : undefined}
          >
            Upload Backup
          </FileUploadButton>
          <Button variant="secondary" onClick={handlePreviewCurrent}>
            Preview Current DB
          </Button>
        </>
      }
      tabs={{
        activeTab: activeTab,
        onTabChange: (value: string) => setActiveTab(value as DatabaseType),
        tabsList: [
          { value: "postgresql", label: "PostgreSQL" },
          { value: "mongodb", label: "MongoDB" },
        ],
      }}
    >
      {isLogModalOpen && (
        <LogModal content={logModalContent} onClose={closeLogModal} />
      )}

      {isRestoreModalOpen && selectedBackupForRestore && (
        <RestoreModal
          backupName={selectedBackupForRestore}
          onClose={(): void => {
            setIsRestoreModalOpen(false);
            setSelectedBackupForRestore(null);
          }}
          onConfirm={(t: boolean): void => { void handleRestoreConfirm(t); }}
        />
      )}

      <ConfirmDialog
        open={!!backupToDelete}
        onOpenChange={(open: boolean) => !open && setBackupToDelete(null)}
        onConfirm={(): void => { void handleConfirmDelete(); }}
        title="Delete Backup"
        description={`Are you sure you want to delete backup "${backupToDelete}"? This cannot be undone.`}
        confirmText="Delete"
        variant="destructive"
      />

      {isProd ? (
        <div className="mb-6 rounded-lg border border-amber-500/30 bg-amber-500/10 px-4 py-3 text-sm text-amber-100">
          Backups are disabled in production. Create or upload backups in a non-production environment.
        </div>
      ) : null}
      <SectionPanel className="p-6">
        <DataTable
          columns={getDatabaseColumns({
            onPreview: handlePreview,
            onRestoreRequest: handleRestoreRequest,
            onDeleteRequest: (name: string): void => { void handleDeleteRequest(name); },
          })}
          data={data}
          initialSorting={[{ id: "lastModifiedAt", desc: true }]}
          sortingStorageKey={`stardb:database-backups:${activeTab}:sorting`}
        />
      </SectionPanel>
    </AdminPageLayout>
  );
}

import { useState, useEffect, useCallback } from "react";
import type { UseNoteFiltersProps } from "@/features/notesapp/types/notes-hooks";
import type { NoteWithRelations } from "@/shared/types/notes";

export type UseNoteFiltersResult = {
  searchQuery: string;
  setSearchQuery: (q: string) => void;
  debouncedSearchQuery: string;
  filterPinned: boolean | undefined;
  setFilterPinned: (v: boolean | undefined) => void;
  filterArchived: boolean | undefined;
  setFilterArchived: (v: boolean | undefined) => void;
  filterFavorite: boolean | undefined;
  setFilterFavorite: (v: boolean | undefined) => void;
  filterTagIds: string[];
  setFilterTagIds: (ids: string[]) => void;
  highlightTagId: string | null;
  setHighlightTagId: (id: string | null) => void;
  page: number;
  setPage: (p: number | ((curr: number) => number)) => void;
  pageSize: number;
  setPageSize: (s: number) => void;
  handleFilterByTag: (tagId: string, setSelectedFolderId: (id: string | null) => void, setSelectedNote: (val: NoteWithRelations | null) => void, setIsEditing: (val: boolean) => void) => void;
  handleToggleFavoritesFilter: (setSelectedFolderId: (id: string | null) => void, setSelectedNote: (val: NoteWithRelations | null) => void, setIsEditing: (val: boolean) => void) => void;
};

export function useNoteFilters({ settings, updateSettings: _updateSettings }: UseNoteFiltersProps): UseNoteFiltersResult {
  const [searchQuery, setSearchQuery] = useState("");
  const [debouncedSearchQuery, setDebouncedSearchQuery] = useState(searchQuery);
  const [filterPinned, setFilterPinned] = useState<boolean | undefined>(undefined);
  const [filterArchived, setFilterArchived] = useState<boolean | undefined>(undefined);
  const [filterFavorite, setFilterFavorite] = useState<boolean | undefined>(undefined);
  const [filterTagIds, setFilterTagIds] = useState<string[]>([]);
  const [highlightTagId, setHighlightTagId] = useState<string | null>(null);

  // Pagination
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(24);

  // Debounce search
  useEffect((): void | (() => void) => {
    const timer = setTimeout((): void => {
      setDebouncedSearchQuery(searchQuery);
    }, 250);
    return (): void => clearTimeout(timer);
  }, [searchQuery]);

  // Reset page when filters change
  useEffect((): void => {

    setPage(1);
  }, [
    debouncedSearchQuery,
    filterPinned,
    filterArchived,
    filterTagIds,
    settings.selectedFolderId,
    settings.sortBy,
    settings.sortOrder,
    settings.selectedNotebookId,
  ]);

  // Clear highlight tag
  useEffect((): void | (() => void) => {
    if (!highlightTagId) return;
    const timer = setTimeout((): void => {
      setHighlightTagId(null);
    }, 2000);
    return (): void => clearTimeout(timer);
  }, [highlightTagId]);

  const handleFilterByTag = useCallback((tagId: string, setSelectedFolderId: (id: string | null) => void, setSelectedNote: (val: NoteWithRelations | null) => void, setIsEditing: (val: boolean) => void): void => {
    setSelectedFolderId(null);
    setFilterTagIds([tagId]);
    setSearchQuery("");
    setSelectedNote(null);
    setIsEditing(false);
    setHighlightTagId(tagId);
  }, []);

  const handleToggleFavoritesFilter = useCallback((setSelectedFolderId: (id: string | null) => void, setSelectedNote: (val: NoteWithRelations | null) => void, setIsEditing: (val: boolean) => void): void => {
    setFilterFavorite((prev: boolean | undefined) => (prev ? undefined : true));
    setSelectedFolderId(null);
    setSelectedNote(null);
    setIsEditing(false);
  }, []);

  return {
    searchQuery,
    setSearchQuery,
    debouncedSearchQuery,
    filterPinned,
    setFilterPinned,
    filterArchived,
    setFilterArchived,
    filterFavorite,
    setFilterFavorite,
    filterTagIds,
    setFilterTagIds,
    highlightTagId,
    setHighlightTagId,
    page,
    setPage,
    pageSize,
    setPageSize,
    handleFilterByTag,
    handleToggleFavoritesFilter,
  };
}

"use client";

import { Button, useToast, Input, Label, SectionPanel, SectionHeader } from "@/shared/ui";
import { AdminPageLayout } from "@/shared/components/AdminPageLayout"; // Added import
import { useEffect, useState, useMemo, useCallback } from "react";
import { MoreVertical } from "lucide-react";
import { logClientError } from "@/features/observability";

import { useNoteSettings } from "@/features/notesapp/hooks/NoteSettingsContext";
import { useNotebooks } from "@/features/notesapp/api/useNoteQueries";
import {
  useCreateNotebook,
  useUpdateNotebook,
  useDeleteNotebook,
} from "@/features/notesapp/api/useNoteMutations";
import type { NotebookRecord } from "@/shared/types/notes";
import { useRouter } from "next/navigation";

export function AdminNotesNotebooksPage(): React.JSX.Element {
  const { toast } = useToast();
  const { settings, updateSettings } = useNoteSettings();
  const { selectedNotebookId } = settings;
  const router = useRouter();
  const [name, setName] = useState("");
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editingName, setEditingName] = useState("");
  const [menuNotebookId, setMenuNotebookId] = useState<string | null>(null);

  const notebooksQuery = useNotebooks();
  const notebooks = useMemo((): NotebookRecord[] => notebooksQuery.data ?? [], [notebooksQuery.data]);
  const loading = notebooksQuery.isPending;

  const createNotebook = useCreateNotebook();
  const updateNotebook = useUpdateNotebook();
  const deleteNotebook = useDeleteNotebook();

  useEffect((): void => {
    if (!selectedNotebookId && notebooks.length > 0) {
      updateSettings({ selectedNotebookId: notebooks[0]!.id });
    }
  }, [selectedNotebookId, notebooks, updateSettings]);

  const handleCreate = async (): Promise<void> => {
    if (!name.trim()) {
      toast("Notebook name is required", { variant: "error" });
      return;
    }
    try {
      await createNotebook.mutateAsync({ name: name.trim() });
      setName("");
      toast("Notebook created", { variant: "success" });
    } catch (error: unknown) {
      logClientError(error, { context: { source: "AdminNotesNotebooksPage", action: "createNotebook", name } });
      toast("Failed to create notebook", { variant: "error" });
    }
  };

  const handleEditStart = useCallback((notebook: NotebookRecord): void => {
    setEditingId(notebook.id);
    setEditingName(notebook.name);
    setMenuNotebookId(null);
  }, []);

  const handleEditCancel = useCallback((): void => {
    setEditingId(null);
    setEditingName("");
  }, []);

  const handleUpdate = async (id: string): Promise<void> => {
    if (!editingName.trim()) {
      toast("Notebook name is required", { variant: "error" });
      return;
    }
    try {
      await updateNotebook.mutateAsync({ id, name: editingName.trim() });
      toast("Notebook updated", { variant: "success" });
      handleEditCancel();
    } catch (error: unknown) {
      logClientError(error, { context: { source: "AdminNotesNotebooksPage", action: "updateNotebook", id } });
      toast("Failed to update notebook", { variant: "error" });
    }
  };

  const handleDelete = async (id: string): Promise<void> => {
    if (!confirm("Delete this notebook and all its notes/tags/folders?")) return;
    try {
      await deleteNotebook.mutateAsync(id);
      if (selectedNotebookId === id) {
        updateSettings({ selectedNotebookId: null });
      }
      toast("Notebook deleted", { variant: "success" });
    } catch (error: unknown) {
      logClientError(error, { context: { source: "AdminNotesNotebooksPage", action: "deleteNotebook", id } });
      toast("Failed to delete notebook", { variant: "error" });
    }
  };

  const handleDuplicate = async (notebook: NotebookRecord): Promise<void> => {
    const baseName = notebook.name.trim();
    const existing = notebooks
      .filter((item: NotebookRecord): boolean => item.name.startsWith(baseName))
      .map((item: NotebookRecord): number => {
        const match = item.name.match(/\((\d+)\)$/);
        return match ? Number(match[1]) : 0;
      });
    const nextNumber = existing.length > 0 ? Math.max(...existing) + 1 : 1;
    const newName = `${baseName} (${nextNumber})`;
    try {
      await createNotebook.mutateAsync({ name: newName });
      toast("Notebook duplicated", { variant: "success" });
    } catch (error: unknown) {
      logClientError(error, { context: { source: "AdminNotesNotebooksPage", action: "duplicateNotebook", originalId: notebook.id } });
      toast("Failed to duplicate notebook", { variant: "error" });
    } finally {
      setMenuNotebookId(null);
    }
  };

  if (loading) return <div className="text-sm text-gray-400">Loading notebooks...</div>;


  return (
    <AdminPageLayout
      title="Notebooks"
      description="Create and manage notebooks. Notes, folders, and tags are scoped per notebook."
    >
      <div className="max-w-3xl space-y-6">
        <SectionPanel className="p-6">
          <SectionHeader title="Create Notebook" size="sm" className="mb-4" />
          <div className="flex flex-col gap-4 sm:flex-row sm:items-end">
            <div className="flex-1">
              <Label className="mb-2 block text-sm font-medium text-gray-200">
                Notebook Name
              </Label>
              <Input
                type="text"
                value={name}
                onChange={(event: React.ChangeEvent<HTMLInputElement>): void => setName(event.target.value)}
                className="w-full"
                placeholder="Enter notebook name"
              />
            </div>
            <Button onClick={(): void => { void handleCreate(); }} disabled={createNotebook.isPending}>
              {createNotebook.isPending ? "Saving..." : "Create"}
            </Button>
          </div>
        </SectionPanel>

        <SectionPanel className="p-6">
          <SectionHeader
            title="Your Notebooks"
            size="sm"
            className="mb-4"
            actions={(
              <Button variant="outline" onClick={(): void => { void notebooksQuery.refetch(); }}>
                Refresh
              </Button>
            )}
          />
          {loading ? (
            <div className="text-sm text-gray-400">Loading notebooks...</div>
          ) : notebooks.length === 0 ? (
            <div className="text-sm text-gray-500">No notebooks created yet.</div>
          ) : (
            <div className="grid gap-3 sm:grid-cols-2">
              {notebooks.map((notebook: NotebookRecord) => {
                const isEditing = editingId === notebook.id;
                const isActive = selectedNotebookId === notebook.id;
                return (
                  <SectionPanel
                    key={notebook.id}
                    variant="subtle"
                    className="flex cursor-pointer items-center justify-between gap-3 px-4 py-3 transition hover:border-border/60"
                    onClick={(): void => {
                      updateSettings({ selectedNotebookId: notebook.id });
                      router.push("/admin/notes");
                    }}
                  >
                    <div className="flex flex-1 items-center gap-3">
                      {isEditing ? (
                        <div className="flex flex-1 flex-col gap-2 sm:flex-row sm:items-center">
                          <Input
                            type="text"
                            value={editingName}
                            onChange={(event: React.ChangeEvent<HTMLInputElement>): void => setEditingName(event.target.value)}
                            className="w-full"
                          />
                        </div>
                      ) : (
                        <div className="flex flex-col">
                          <Button
                            type="button"
                            onClick={(event: React.MouseEvent): void => {
                              event.stopPropagation();
                              handleEditStart(notebook);
                            }}
                            className="text-left text-sm text-gray-200 hover:text-white"
                          >
                            {notebook.name}
                          </Button>
                          {isActive && (
                            <span className="text-[11px] text-blue-300">Active</span>
                          )}
                        </div>
                      )}
                    </div>
                    <div className="flex items-center gap-2">
                      {isEditing ? (
                        <>
                          <Button
                            variant="outline"
                            size="sm"
                            onClick={(event: React.MouseEvent): void => {
                              event.stopPropagation();
                              void handleUpdate(notebook.id);
                            }}
                            disabled={updateNotebook.isPending}
                          >
                            Save
                          </Button>
                          <Button
                            variant="ghost"
                            size="sm"
                            onClick={(event: React.MouseEvent): void => {
                              event.stopPropagation();
                              handleEditCancel();
                            }}
                          >
                            Cancel
                          </Button>
                        </>
                      ) : (
                        <></>
                      )}
                      {!isEditing && (
                        <div className="relative">
                          <Button
                            type="button"
                            onClick={(event: React.MouseEvent): void => {
                              event.stopPropagation();
                              setMenuNotebookId((prev: string | null): string | null =>
                                prev === notebook.id ? null : notebook.id
                              );
                            }}
                            className="rounded p-1 text-gray-400 hover:bg-muted/50 hover:text-gray-200"
                            aria-label={`Notebook actions for ${notebook.name}`}
                          >
                            <MoreVertical size={16} />
                          </Button>
                          {menuNotebookId === notebook.id && (
                            <>
                              <div
                                className="fixed inset-0 z-40"
                                onClick={(): void => setMenuNotebookId(null)}
                              />
                              <div className="absolute right-0 top-full z-50 mt-2 w-44 rounded-md border bg-card p-1 shadow-lg">
                                <Button
                                  type="button"
                                  onClick={(event: React.MouseEvent): void => {
                                    event.stopPropagation();
                                    handleEditStart(notebook);
                                    setMenuNotebookId(null);
                                  }}
                                  onClickCapture={(event: React.MouseEvent): void => event.stopPropagation()}
                                  className="flex w-full items-center gap-2 rounded px-2 py-1.5 text-xs text-gray-200 hover:bg-muted/50"
                                >
                                  Rename
                                </Button>
                                <Button
                                  type="button"
                                  onClick={(event: React.MouseEvent): void => {
                                    event.stopPropagation();
                                    void handleDuplicate(notebook);
                                  }}
                                  onClickCapture={(event: React.MouseEvent): void => event.stopPropagation()}
                                  className="flex w-full items-center gap-2 rounded px-2 py-1.5 text-xs text-gray-200 hover:bg-muted/50"
                                >
                                  Duplicate
                                </Button>
                                <Button
                                  type="button"
                                  onClick={(event: React.MouseEvent): void => {
                                    event.stopPropagation();
                                    void handleDelete(notebook.id);
                                  }}
                                  onClickCapture={(event: React.MouseEvent): void => event.stopPropagation()}
                                  className="flex w-full items-center gap-2 rounded px-2 py-1.5 text-xs text-red-300 hover:bg-muted/50"
                                >
                                  Delete
                                </Button>
                              </div>
                            </>
                          )}
                        </div>
                      )}
                    </div>
                  </SectionPanel>
                );
              })}
            </div>
          )}
        </SectionPanel>
      </div>
    </AdminPageLayout>
  );
}

